import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface DriverInfo {
  name: string;
  rating: number;
  car: string;
}

interface RideshareData {
  estimatedFare: number;
  arrivalTime: string;
  driver: DriverInfo;
}

export default function Widget() {
  const rideshareData = response.data as RideshareData;
  const { estimatedFare, arrivalTime, driver } = rideshareData;
  const { name, rating, car } = driver;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#333' }} elevation={2}>
      <CardContent sx={{ p: 2.5, color: '#FFF' }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Ride Share Info
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Estimated Fare
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              ${estimatedFare.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Arrival Time: {arrivalTime}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Driver Details
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Name: ${name}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#424242' }} />
              <Chip label={`Rating: ${rating}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#424242' }} />
              <Chip label={`Car: ${car}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#424242' }} />
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
